// Map Custom Fields - Extract and format contact data
const customFieldMapping = {
  'YOUR_TAG_1_ID': 'tag_1',
  'YOUR_TAG_2_ID': 'vehicle',
  'YOUR_NOTES_FIELD_ID': 'message',
  'YOUR_SERVICES_INTERESTED_FIELD_ID': 'services_interested',
  'YOUR_DESIRED_PACKAGES_FIELD_ID': 'desired_packages',
  'YOUR_SERVICES_CHECK_FIELD_ID': 'services_interested_check'
};

const contact = $json.contact;
const opportunity = $('Limit 10').item.json;

const output = {
  contact_id: contact.id,
  opportunity_id: opportunity.id,
  first_name: contact.firstName || 'unknown' 
};

// Map custom fields - handle both strings and arrays
if (contact.customFields && Array.isArray(contact.customFields)) {
  contact.customFields.forEach(field => {
    const mappedName = customFieldMapping[field.id];
    if (mappedName && field.value) {
      // Handle arrays (checkboxes, multi-select)
      if (Array.isArray(field.value)) {
        if (field.value.length > 0) {
          output[mappedName] = field.value.join(', ');
        }
      }
      // Handle strings
      else if (typeof field.value === 'string' && field.value.trim() !== '') {
        output[mappedName] = field.value.trim();
      }
      // Handle other types (numbers, booleans, etc.)
      else if (field.value !== null && field.value !== undefined) {
        output[mappedName] = field.value;
      }
    }
  });
}

return output;

// Field IDs
const ENTRY_DATE_FIELD_ID = 'YOUR_ENTRY_DATE_FIELD_ID';
const LAST_SENT_FIELD_ID = 'YOUR_LAST_SENT_FIELD_ID';

// UTC timezone calculations
const ONE_DAY_MS = 24 * 60 * 60 * 1000;
const nowMs = Date.now();

// Calculate today at midnight UTC
const todayMidnightUTC = Math.floor(nowMs / ONE_DAY_MS) * ONE_DAY_MS;

// Message days
const MESSAGE_DAYS = [30, 60, 90, 120, 150, 180, 210, 240, 270, 300, 330, 360];

// Collect opportunities from ALL pages
const items = $input.all();
let allOpportunities = [];
for (const item of items) {
  const pageOpportunities = item.json.opportunities || [];
  allOpportunities = allOpportunities.concat(pageOpportunities);
}

// DEDUPLICATION: Remove duplicate opportunities by ID
const uniqueOpportunities = [];
const seenIds = new Set();
for (const opp of allOpportunities) {
  if (!seenIds.has(opp.id)) {
    seenIds.add(opp.id);
    uniqueOpportunities.push(opp);
  }
}

// Filter opportunities
const filtered = uniqueOpportunities.filter(opp => {
  const customFields = opp.customFields || [];

  // Find entry date
  const entryField = customFields.find(f => f.id === ENTRY_DATE_FIELD_ID);
  if (!entryField || !entryField.fieldValueDate) {
    return false;
  }

  // Entry date is midnight UTC (stored by GHL)
  const entryMidnightUTC = entryField.fieldValueDate;

  // Calculate days since entry (both are midnight UTC)
  const daysSinceEntry = Math.floor((todayMidnightUTC - entryMidnightUTC) / ONE_DAY_MS);

  // Check if today is a message day
  if (!MESSAGE_DAYS.includes(daysSinceEntry)) {
    return false;
  }

  // Find last sent date
  const lastSentField = customFields.find(f => f.id === LAST_SENT_FIELD_ID);
  if (!lastSentField || !lastSentField.fieldValueDate) {
    return true; // No last sent date, so send message
  }

  // Last sent is also midnight UTC
  const lastSentMidnightUTC = lastSentField.fieldValueDate;

  // Compare calendar dates (safer than raw timestamp comparison)
  const lastSentDate = new Date(lastSentMidnightUTC).toISOString().split('T')[0];
  const todayDate = new Date(todayMidnightUTC).toISOString().split('T')[0];
  return lastSentDate !== todayDate;
});

// Single summary log for monitoring
console.log(`Active Nurture Dispatcher: ${filtered.length} messages scheduled (from ${uniqueOpportunities.length} total opportunities)`);

// Return in n8n format
return filtered.map(opp => ({ json: opp }));

// Get messages array from API response
const messagesData = $input.item.json.messages;

// Handle cases where there are no messages
if (!messagesData || !messagesData.messages || messagesData.messages.length === 0) {
  return {
    json: {
      formatted_sms_history: "(No previous conversation history)"
    }
  };
}

// Get messages array - API returns newest first, we want oldest first
let messages = messagesData.messages;

// Limit to 20 most recent messages (take last 20 from the array)
if (messages.length > 20) {
  messages = messages.slice(0, 20);
}

// Reverse to get chronological order (oldest → newest)
messages.reverse();

// Format each message
const formattedMessages = messages.map(msg => {
  // Determine sender label
  const sender = msg.direction === 'outbound' ? 'YOUR_BUSINESS_NAME' : 'CUSTOMER';

  // Format date - just month, day, year
  const date = new Date(msg.dateAdded);
  const month = date.toLocaleString('en-US', { month: 'short' });
  const day = date.getDate();
  const year = date.getFullYear();

  const formattedDate = `[${month} ${day}, ${year}]`;

  // Return formatted message
  return `${formattedDate} ${sender}: ${msg.body}`;
});

// Join with newlines
const formatted_sms_history = formattedMessages.join('\n');

return {
  json: {
    formatted_sms_history
  }
};

// Get notes array from API response
const notesData = $input.item.json.notes;

// Handle cases where there are no notes
if (!notesData || notesData.length === 0) {
  return {
    json: {
      formatted_customer_notes: "(No previous calls or notes)"
    }
  };
}

// Notes come from API newest first, reverse to chronological order
const notes = [...notesData].reverse();

// Format each note - extract only relevant sections
const formattedNotes = notes.map(note => {
  const date = new Date(note.dateAdded);
  const dateStr = date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });

  let noteText = note.bodyText.trim();

  // Find where unwanted sections start (new clean format)
  const performanceIndex = noteText.indexOf('📊 PERFORMANCE NOTES');
  const followupIndex = noteText.indexOf('💬 FOLLOW-UP SMS DRAFT');

  // Find the earliest cutoff point
  let cutoffIndex = -1;
  if (performanceIndex !== -1 && followupIndex !== -1) {
    cutoffIndex = Math.min(performanceIndex, followupIndex);
  } else if (performanceIndex !== -1) {
    cutoffIndex = performanceIndex;
  } else if (followupIndex !== -1) {
    cutoffIndex = followupIndex;
  }

  // Cut off unwanted sections
  let filteredText = cutoffIndex !== -1 
    ? noteText.substring(0, cutoffIndex).trim()
    : noteText;

  // Clean up: remove emojis from section headers, keep structure intact
  filteredText = filteredText
    .replace(/⛵ SERVICE & CONTEXT/g, 'SERVICE & CONTEXT')
    .replace(/🚗 VEHICLE & CONTEXT/g, 'VEHICLE & CONTEXT')
    .replace(/🎯 GOALS & PRIORITIES/g, 'GOALS & PRIORITIES')
    .replace(/💰 OFFER & PRICING/g, 'OFFER & PRICING')
    .replace(/➡️ NEXT STEPS/g, 'NEXT STEPS')
    .replace(/\n{3,}/g, '\n\n') // Collapse excessive newlines
    .trim();

  return `${dateStr}\n${filteredText}`;
});

const formatted_customer_notes = formattedNotes.join('\n\n');

return {
  json: {
    formatted_customer_notes
  }
};

// Get all formatted data from previous nodes
const customerData = $('Gather Customer Data').item.json;
const smsHistory = $('Format Conversation History').item.json.formatted_sms_history;
const customerNotes = $('Format Customer Notes').item.json.formatted_customer_notes;
const opportunity = $('Filter Opportunities by Date').item.json;

// Get current promo from global variable
const currentPromo = $vars.CURRENT_PROMO || null;

// Build customer info section
const customerInfoLines = [];
customerInfoLines.push(`Name: ${customerData.first_name || 'Not provided'}`);

if (customerData.asset_description) {
  customerInfoLines.push(`Asset: ${customerData.asset_description}`);
}

if (customerData.vehicle) {
  customerInfoLines.push(`Vehicle: ${customerData.vehicle}`);
}

// Build service interest section - show both if both exist
const serviceInterests = [];
if (customerData.services_interested_check) {
  serviceInterests.push(customerData.services_interested_check);
}
if (customerData.services_interested) {
  serviceInterests.push(customerData.services_interested);
}
if (serviceInterests.length > 0) {
  customerInfoLines.push(`Service Interest: ${serviceInterests.join(', ')}`);
}

if (customerData.desired_packages) {
  customerInfoLines.push(`Package Interest: ${customerData.desired_packages}`);
}

if (customerData.notes) {
  customerInfoLines.push(`Notes: ${customerData.notes}`);
}

const customerInfo = customerInfoLines.join('\n');

// Build user prompt
const userPrompt = `Customer Info:
${customerInfo}
${currentPromo ? `\nCurrent Promo:\n${currentPromo}\n` : ''}
${customerNotes !== '(No previous calls or notes)' ? `Customer Notes:\n${customerNotes}\n` : 'No previous calls or notes.\n'}
Conversation History:
${smsHistory}`;

return {
  json: {
    chatInput: userPrompt,
    contact_id: customerData.contact_id,
    opportunity_id: opportunity.id
  }
};

// Simple UTC midnight calculation
const nowMs = Date.now();
const oneDayMs = 24 * 60 * 60 * 1000;

const midnightUTC = Math.floor(nowMs / oneDayMs) * oneDayMs;

// Convert to YYYY-MM-DD
const date = new Date(midnightUTC);
const year = date.getUTCFullYear();
const month = String(date.getUTCMonth() + 1).padStart(2, '0');
const day = String(date.getUTCDate()).padStart(2, '0');
const lastSentDate = `${year}-${month}-${day}`;

return {
  json: {
    ...($input.item.json),
    lastSentDate: lastSentDate
  }
};

// Get data from earlier nodes
const promptData = $('Build User Prompt').item.json;
const opportunity = $('Filter Opportunities by Date').item.json;

// Field ID for entry_date
const ENTRY_DATE_FIELD_ID = 'YOUR_ENTRY_DATE_FIELD_ID';

// Get entry_date from opportunity custom fields
const entryField = opportunity.customFields?.find(f => f.id === ENTRY_DATE_FIELD_ID);
const entryDate = entryField?.fieldValueDate;

// Calculate days since entry (same logic as other dispatchers)
const ONE_DAY_MS = 24 * 60 * 60 * 1000;
const todayMidnightUTC = Math.floor(Date.now() / ONE_DAY_MS) * ONE_DAY_MS;
const daysSinceEntry = entryDate 
  ? Math.floor((todayMidnightUTC - entryDate) / ONE_DAY_MS)
  : null;

return {
  timestamp: Date.now(),
  contact_id: promptData.contact_id,
  event_type: 'message_sent',
  pipeline_stage: 'Monthly',
  days_since_entry: daysSinceEntry,
  weekday: new Date().toLocaleDateString('en-US', { weekday: 'long' })
};
